const form = $input.first().json;

const profile = {
  nama: form['Nama Bisnis'],
  jenis: form['Jenis Usaha'],
  gaya: form['Gaya Bahasa'],
  produk: form['Produk/Layanan Utama'],
  info: form['Info Tambahan'] || 'Tidak ada info tambahan.'
};

const categories = [
  {
    category: 'greeting',
    label: 'Sapaan & Pembuka',
    description: 'Template pesan pertama saat pelanggan baru memulai chat. Tujuannya membangun kesan pertama yang positif dan mengajak pelanggan menyampaikan kebutuhannya.',
    angles: ['Ramah & antusias dengan emoji', 'Profesional & to-the-point', 'Membangun kedekatan personal', 'Menyapa + langsung tanya kebutuhan', 'Menyapa berdasarkan waktu (pagi/siang/malam)'],
    count: 7
  },
  {
    category: 'pricing',
    label: 'Info Harga & Penawaran',
    description: 'Template untuk menyampaikan harga produk/layanan. Harus meyakinkan pelanggan bahwa harga sebanding dengan kualitas.',
    angles: ['Fokus harga terjangkau/diskon', 'Fokus value & kualitas premium', 'Fokus garansi & keamanan belanja', 'Perbandingan dengan kompetitor', 'Bundling & paket hemat'],
    count: 7
  },
  {
    category: 'info',
    label: 'Info Produk, Stok & Fitur',
    description: 'Template untuk memberikan informasi detail tentang produk: fitur, ketersediaan stok, varian, dan keunggulan.',
    angles: ['Deskripsi fitur utama', 'Stok tersedia & urgensi', 'Stok kosong & alternatif', 'Perbandingan antar varian', 'Testimoni & social proof'],
    count: 7
  },
  {
    category: 'objection',
    label: 'Handling Keberatan',
    description: 'Template untuk menangani keberatan pelanggan (harga terlalu mahal, ragu kualitas, takut penipuan, dll). Harus empatis dan meyakinkan.',
    angles: ['Empati + penjelasan value', 'Social proof & testimoni', 'Garansi & jaminan keamanan', 'Perbandingan harga vs manfaat'],
    count: 5
  },
  {
    category: 'conversion',
    label: 'Ajakan Order / CTA',
    description: 'Template Call-to-Action untuk mengajak pelanggan melakukan pemesanan. Harus sopan tapi persuasif.',
    angles: ['Soft selling (ajakan lembut)', 'Urgency (stok/promo terbatas)', 'Kemudahan proses order', 'Follow-up setelah konsultasi'],
    count: 5
  },
  {
    category: 'closing',
    label: 'Penutup Percakapan',
    description: 'Template untuk mengakhiri percakapan dengan kesan baik. Bisa setelah transaksi selesai atau setelah menjawab pertanyaan.',
    angles: ['Terima kasih hangat', 'Tawaran bantuan lanjutan', 'Ucapan doa/harapan baik', 'Reminder untuk kembali lagi'],
    count: 5
  },
  {
    category: 'complaint',
    label: 'Penanganan Keluhan',
    description: 'Template untuk merespons keluhan/komplain pelanggan. Harus menunjukkan empati tinggi, permintaan maaf, dan solusi konkret.',
    angles: ['Empati + permintaan maaf', 'Solusi langsung + timeline', 'Eskalasi ke tim terkait', 'Follow-up setelah penyelesaian'],
    count: 5
  }
];

// Output 7 items, satu per kategori
return categories.map(cat => ({
  json: {
    ...cat,
    profile
  }
}));

const item = $input.first().json;
const p = item.profile;

const systemPrompt = `Kamu adalah Spesialis Copywriter Customer Service WhatsApp/Telegram.

PROFIL BISNIS:
- Nama: ${p.nama}
- Jenis: ${p.jenis}
- Gaya Bahasa: ${p.gaya}
- Produk/Layanan: ${p.produk}
- Info Tambahan: ${p.info}

TUGAS: Buat ${item.count} template pesan untuk kategori "${item.label}".
Deskripsi kategori: ${item.description}

SUDUT PANDANG (ANGLES) — Gunakan angle yang berbeda untuk setiap variasi:
${item.angles.map((a, i) => `${i+1}. ${a}`).join('\n')}

ATURAN:
1. Setiap variasi HARUS punya nada/struktur kalimat yang BERBEDA SIGNIFIKAN
2. Gunakan placeholder {variabel} untuk data dinamis: {nama_produk}, {harga}, {link_order}, {jam_buka}, {nama_pelanggan}, {masalah}
3. Gaya bahasa KONSISTEN: ${p.gaya}
4. Panjang template: 1-4 kalimat (cocok chat)
5. JANGAN gunakan numbering/bullet di dalam isi template
6. JANGAN tambahkan penjelasan apapun, HANYA isi template

FORMAT OUTPUT (WAJIB IKUTI PERSIS):
Untuk setiap template, tulis PERSIS format ini:

---
**Nama:** [Nama singkat template]
**Angle:** [Angle yang dipakai]
**Isi:**
[Isi template pesan di sini]
---

Mulai sekarang, tulis ${item.count} template.`;

return [{
  json: {
    category: item.category,
    label: item.label,
    count: item.count,
    systemPrompt,
    userPrompt: `Buat ${item.count} template pesan CS untuk kategori "${item.label}" bisnis "${p.nama}". Gunakan format yang diminta.`
  }
}];

const raw = $input.first().json.text || $input.first().json.response?.text || $input.first().json.output || '';
const category = $('Build Prompt').first().json.category;
const label = $('Build Prompt').first().json.label;

// Build markdown section for this category
let section = `\n## ${label} (${category})\n\n`;
section += raw.trim();
section += '\n\n';

return [{
  json: {
    category,
    label,
    markdown_section: section
  }
}];

// Collect all markdown sections from all loop iterations
const items = $input.all();
const form = $('Input Profil Bisnis').first().json;

const nama = form['Nama Bisnis'];
const jenis = form['Jenis Usaha'];
const gaya = form['Gaya Bahasa'];
const produk = form['Produk/Layanan Utama'];
const info = form['Info Tambahan'] || '-';
const tanggal = new Date().toLocaleDateString('id-ID', { year: 'numeric', month: 'long', day: 'numeric' });

let doc = `# Template Pesan CS — ${nama}\n\n`;
doc += `**Tanggal:** ${tanggal}\n`;
doc += `**Jenis Usaha:** ${jenis}\n`;
doc += `**Gaya Bahasa:** ${gaya}\n`;
doc += `**Produk/Layanan:** ${produk}\n`;
doc += `**Info Tambahan:** ${info}\n`;
doc += `\n---\n`;

for (const item of items) {
  doc += item.json.markdown_section || '';
}

doc += `\n---\n*Dokumen ini di-generate otomatis oleh AI Template Generator.*\n`;

const fileName = `templates_${nama.replace(/[^a-zA-Z0-9]/g, '_').toLowerCase()}_${new Date().toISOString().slice(0,10)}.md`;

return [{
  json: {
    fileName,
    totalCategories: items.length,
    preview: doc.substring(0, 500) + '...'
  },
  binary: {
    data: {
      data: Buffer.from(doc, 'utf-8').toString('base64'),
      mimeType: 'text/markdown',
      fileName
    }
  }
}];
